PRIME = 998244353

def power(a, b):
    res = 1
    a = a % PRIME
    while b > 0:
        if b % 2 == 1:
            res = res * a % PRIME
        a = a * a % PRIME
        b = b // 2
    return res

n = int(input())

if n == 1:
    print(499122177)
elif n == 2:
